const source = $input.first().json;
const jobId = source.jobId;
if (!jobId) throw new Error('Missing jobId for cover generation');
const order = source.order || {};
const text = source.text || {};
const COVER_ART_TARGET = {
  role: 'front_cover_framed_art',
  finalSpreadSizeMm: [268.5, 136],
  frameAspectRatio: 'about 1.46:1 landscape',
  placement: 'front-cover white image frame in the PPTX-derived cover template',
  safety: 'do not draw the back cover or spine; keep heroes and key objects comfortably inside the frame so the renderer can crop-cover without cutting them',
};

async function apiRequest(options) {
  return await this.helpers.httpRequest({
    ...options,
    headers: {
      Authorization: 'Bearer ' + $env.FAIRYTELLER_API_TOKEN,
      ...(options.headers || {}),
    },
    json: true,
  });
}

async function patchJob(body) {
  return await apiRequest.call(this, {
    method: 'PATCH',
    url: 'https://fairyteller.ru/api/fairyteller/jobs/' + jobId,
    headers: { 'Content-Type': 'application/json' },
    body,
    timeout: 30000,
  });
}

async function fetchJsonArtifact(fileName) {
  return await apiRequest.call(this, {
    method: 'GET',
    url: 'https://fairyteller.ru/api/fairyteller/jobs/' + jobId + '/artifacts/' + fileName,
    timeout: 30000,
  });
}

async function fetchImageBase64(url) {
  if (!url) return null;
  const absoluteUrl = url.startsWith('http') ? url : 'https://fairyteller.ru' + url;
  const separator = absoluteUrl.includes('?') ? '&' : '?';
  const payload = await apiRequest.call(this, {
    method: 'GET',
    url: absoluteUrl + separator + 'base64=1',
    timeout: 30000,
  });
  if (!payload?.contentBase64) throw new Error('Fetched reference image has no base64 content');
  return { mimeType: payload.contentType || 'image/png', data: payload.contentBase64, bytes: payload.bytes || Buffer.from(payload.contentBase64, 'base64').length };
}

async function fetchReferenceImages(visuals, visualBible) {
  const cards = (visualBible?.heroReferenceCards || visuals.heroReferenceCards || []).filter((card) => card.status === 'ready' && card.url);
  const images = [];
  for (const card of cards) {
    const image = await fetchImageBase64.call(this, card.url);
    if (image?.data) {
      images.push({ ...image, type: 'hero_card', hero: card.hero, name: card.name || '', ageGroup: card.ageGroup || 'unknown', url: card.url });
    }
  }

  const expectedHeroCount = (visualBible?.characters || visuals.characters || order.heroes || [])
    .filter((hero) => hero?.name || hero?.description || hero?.referenceCardUrl || hero?.hasPhoto || hero?.ageGroup).length;
  const readyCardHeroCount = new Set(images.filter((image) => image.type === 'hero_card').map((image) => Number(image.hero))).size;
  const hasPortraitSheet = visuals.portraitSheet?.status === 'ready' && visuals.portraitSheet?.url;
  const needsPortraitSheet = hasPortraitSheet && (!images.length || (expectedHeroCount > 0 && readyCardHeroCount < expectedHeroCount));

  if (needsPortraitSheet) {
    const image = await fetchImageBase64.call(this, visuals.portraitSheet.url);
    if (image?.data) {
      images.push({ ...image, type: 'portrait_sheet', hero: null, name: 'combined reference sheet', ageGroup: 'mixed', url: visuals.portraitSheet.url });
    }
  }

  return images;
}

function referenceMapLines(referenceImages) {
  return referenceImages.map((image, index) => {
    if (image.type === 'hero_card') return 'Attached reference image ' + (index + 1) + ' = Hero ' + image.hero + ' (' + (image.name || 'unnamed') + '), age group ' + (image.ageGroup || 'unknown');
    return 'Attached reference image ' + (index + 1) + ' = combined hero reference sheet';
  }).join('\n');
}

function cleanText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function storySummary(fullText) {
  const chapters = fullText?.text?.chapters || text.chapters || [];
  return chapters.map((chapter) => 'Глава ' + chapter.n + ': ' + (chapter.title || '') + '. ' + (chapter.summary || cleanText(chapter.text || (chapter.textBlocks || []).join(' ')).slice(0, 500))).join('\n');
}

function characterLine(hero) {
  const label = hero.name || ('Hero ' + (hero.hero || hero.n || ''));
  const age = hero.ageGroup || 'unknown';
  const ageNote = age === 'unknown' ? 'age group: unknown/infer from reference image' : 'age group: ' + age + ' (mandatory)';
  const ref = hero.referenceCardUrl ? 'reference card: ' + hero.referenceCardUrl : '';
  return [label, ageNote, ref, hero.description || '', hero.relation ? 'relation: ' + hero.relation : ''].filter(Boolean).join('; ');
}

function coverPrompt({ visualBible, fullText, referenceImages }) {
  const bible = fullText?.text?.bible || text.bible || {};
  const stylePrompt = visualBible?.style?.prompt || order.illustrationStylePrompt || order.illustrationStyle || 'photorealistic cinematic book illustration, realistic people, natural light, print-ready composition';
  const world = visualBible?.world || {};
  const characters = (visualBible?.characters || order.heroes || []).map((hero) => {
    if (hero.name || hero.description || hero.relation || hero.ageGroup) {
      return characterLine(hero);
    }
    return '';
  }).filter(Boolean).join('\n');
  const title = bible.bookTitle || fullText?.text?.preview?.title || text.preview?.title || '';
  const subtitle = bible.subtitle || '';
  const coverSummary = bible.coverSummary || fullText?.text?.preview?.summary || text.preview?.summary || '';
  const referenceMap = referenceMapLines(referenceImages || []);
  const hasHeroCards = (referenceImages || []).some((image) => image.type === 'hero_card');
  const hasPortraitSheet = (referenceImages || []).some((image) => image.type === 'portrait_sheet');
  const referenceInstruction = referenceImages?.length
    ? (hasHeroCards && hasPortraitSheet
      ? 'Use the attached individual hero reference cards where available, and use the attached combined character reference sheet for any hero whose individual card is missing. Treat both as mandatory identity canon for the cover; do not swap, merge, average or reinterpret identities. Preserve exact adult/child/teen/senior age groups, relative height scale, hair, outfits/accessories and silhouettes.'
      : (hasHeroCards
        ? 'Use the attached individual hero reference cards as mandatory identity canon for all heroes on the cover. Each card maps to exactly one hero; do not swap, merge, average or reinterpret identities. Preserve the same faces, exact adult/child/teen/senior age group, relative height scale, hair, outfits/accessories and silhouettes.'
        : 'Use the attached generated character reference sheet as mandatory identity canon for all heroes on the cover. Preserve the same faces, exact adult/child/teen/senior age group, age impression, relative height scale, hair, outfits/accessories and silhouettes.'))
    : 'No reference image is attached; preserve identity from written descriptions.';
  return [
    'Generate an IMAGE only. Do not answer with text.',
    'Create one landscape front-cover framed illustration for a printed square children book.',
    'Final print spread is 268.5 x 136 mm, but this generated artwork is inserted only into the front-cover white image frame. Target artwork frame: about 1.46:1 landscape. Do not create a full wraparound spread, back cover, spine, title panel or border. Compose for the frame itself so the PDF renderer does not need to rescue the crop.',
    'Do not include any readable text, title, letters, logo, UI, captions, watermark, fake typography, labels, signs or book-page layout. Text will be added later in PDF layout.',
    '',
    '[STYLE - highest priority]',
    stylePrompt,
    '',
    '[CHARACTER IDENTITY]',
    referenceInstruction,
    referenceMap ? '[REFERENCE IMAGE MAP]\n' + referenceMap : '',
    '',
    '[FRONT COVER FRAME COMPOSITION]',
    'One strong iconic scene with the main heroes and the important object. It should feel like the promise of the whole story, not a random chapter still. Leave calm negative space in the upper third for a title overlay later, but do not draw text. Keep faces, hands and the important object away from the frame edges so crop-cover placement cannot cut them off.',
    '',
    '[WORLD]',
    'World: ' + (world.title || bible.worldTitle || order.world || ''),
    'World visual language: ' + (world.visual || bible.worldVisual || ''),
    'World motifs: ' + (world.motifs || bible.worldMotifs || ''),
    'World tension: ' + (world.conflict || bible.worldConflict || ''),
    'Location: ' + (world.location || order.location || bible.location || ''),
    'Important object: ' + (world.artifact || order.artifact || bible.artifact || ''),
    '',
    '[BOOK]',
    'Title for context only, do not render it: ' + title,
    'Subtitle for context only, do not render it: ' + subtitle,
    'Cover summary: ' + coverSummary,
    '',
    '[CHARACTERS]',
    characters || 'Use the main heroes from the story.',
    '',
    '[AGE AND ROLE RULE]',
    'Treat each hero age group as mandatory. Children must read as children, adults as adults, teenagers as teenagers, seniors as seniors. Keep relative height/scale and maturity stable; do not swap ages between heroes.',
    '',
    '[WHOLE STORY CONTEXT]',
    storySummary(fullText).slice(0, 3200),
    '',
    '[QUALITY]',
    'Print-ready artwork for the front-cover image frame, coherent anatomy, readable silhouettes, stable style, rich but not cluttered, no text artifacts, no fake letters, no signs, no border, no letterboxing, no white margin.',
  ].join('\n');
}

function findInlineImage(response) {
  return (response.candidates?.[0]?.content?.parts || []).find((part) => part.inlineData?.data);
}
function responseText(response) {
  return (response.candidates?.[0]?.content?.parts || []).map((part) => part.text || '').join(' ').replace(/\s+/g, ' ').trim();
}

await patchJob.call(this, {
  artifacts: { cover: { status: 'generating', requestedAt: new Date().toISOString(), targetPageSizeMm: [268.5, 136] } },
});

try {
  const fullText = await fetchJsonArtifact.call(this, 'full-text.json');
  const visualsArtifact = await fetchJsonArtifact.call(this, 'visuals.json');
  const visuals = visualsArtifact.visuals || {};
  const visualBible = visuals.visualBible || {};
  const referenceImages = await fetchReferenceImages.call(this, visuals, visualBible);
  const prompt = coverPrompt({ visualBible, fullText, referenceImages });
  const requestParts = [{ text: prompt }];
  for (const image of referenceImages) {
    if (image?.data) requestParts.push({ inlineData: { mimeType: image.mimeType || 'image/png', data: image.data } });
  }
  const request = {
    contents: [{ role: 'user', parts: requestParts }],
    generationConfig: { responseModalities: ['TEXT', 'IMAGE'], temperature: 0.35 },
  };
  let response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image:generateContent',
    headers: { 'x-goog-api-key': $env.GEMINI_API_KEY, 'Content-Type': 'application/json' },
    body: request,
    json: true,
    timeout: 180000,
  });
  let part = findInlineImage(response);
  let reason = responseText(response);
  if (!part) {
    const retryPrompt = [
      'Generate an IMAGE only. Landscape front-cover framed artwork, about 1.46:1 aspect ratio.',
      'No text, no letters, no captions, no logos, no watermark, no border, no letterboxing.',
      'Use attached individual hero reference cards or combined character reference sheet as identity canon if present, including exact adult/child/teen/senior age roles and relative height scale. Do not swap hero identities.',
      'One iconic front-cover scene: heroes and important object. Do not draw a back cover, spine, spread layout, title panel, or text zones. Keep faces and key objects away from the frame edges.',
      'Style: ' + (visualBible?.style?.prompt || order.illustrationStylePrompt || order.illustrationStyle || 'book cover illustration'),
      'Story: ' + (fullText?.text?.bible?.coverSummary || text?.bible?.coverSummary || text?.preview?.summary || ''),
    ].join('\n');
    response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image:generateContent',
      headers: { 'x-goog-api-key': $env.GEMINI_API_KEY, 'Content-Type': 'application/json' },
      body: { contents: [{ role: 'user', parts: [{ text: retryPrompt }, ...referenceImages.filter((image) => image?.data).map((image) => ({ inlineData: { mimeType: image.mimeType || 'image/png', data: image.data } }))] }], generationConfig: { responseModalities: ['TEXT', 'IMAGE'], temperature: 0.2 } },
      json: true,
      timeout: 180000,
    });
    part = findInlineImage(response);
    reason = responseText(response) || reason;
  }
  if (!part) {
    throw new Error('Gemini did not return an inline image for cover: ' + (reason || response.promptFeedback?.blockReason || response.candidates?.[0]?.finishReason || 'unknown reason'));
  }
  const mimeType = part.inlineData.mimeType || 'image/png';
  const ext = mimeType.includes('webp') ? 'webp' : mimeType.includes('jpeg') || mimeType.includes('jpg') ? 'jpg' : 'png';
  const fileName = 'cover-spread.' + ext;
  await apiRequest.call(this, {
    method: 'PUT',
    url: 'https://fairyteller.ru/api/fairyteller/jobs/' + jobId + '/files/' + fileName,
    headers: { 'Content-Type': 'application/json' },
    body: { contentType: mimeType, contentBase64: part.inlineData.data },
    timeout: 60000,
  });
  const url = '/api/fairyteller/jobs/' + jobId + '/files/' + fileName;
  const cover = {
    slot: 'cover',
    status: 'ready',
    fileName,
    url,
    absoluteUrl: 'https://fairyteller.ru' + url,
    mimeType,
    bytes: Buffer.from(part.inlineData.data, 'base64').length,
    prompt,
    provider: 'gemini',
    model: 'gemini-2.5-flash-image',
    targetPageSizeMm: COVER_ART_TARGET.finalSpreadSizeMm,
    targetImageFrameAspectRatio: COVER_ART_TARGET.frameAspectRatio,
    targetImagePlacement: COVER_ART_TARGET.placement,
    role: 'front_cover_frame_art_no_text',
    referenceSheetUrl: visualBible?.portraitSheetUrl || null,
    characterReferenceCardUrls: (visualBible?.heroReferenceCards || []).map((card) => card.url).filter(Boolean),
    visualBibleVersion: visualBible?.version || 1,
  };
  const previousJobs = Array.isArray(visuals.imageJobs) ? visuals.imageJobs : [];
  const imageJobs = [cover, ...previousJobs.filter((image) => image.slot !== 'cover')]
    .sort((a, b) => String(a.slot).localeCompare(String(b.slot), 'en', { numeric: true }));
  const updatedVisuals = {
    ...visuals,
    imageJobs,
    imagePrompts: { ...(visuals.imagePrompts || {}), cover: prompt },
    cover: { ...cover, prompt: undefined },
  };
  return [{ json: { ...source, status: 'cover_ready', visuals: updatedVisuals, cover: { ...cover, prompt: undefined } } }];
} catch (error) {
  const message = 'Не удалось подготовить обложку: ' + error.message;
  await patchJob.call(this, { artifacts: { cover: { status: 'failed', error: message } }, error: { message } });
  throw new Error(message);
}
